class DataProcessor {
public:
    std::vector<int> data;

    int processData() {
        int result = 0;
        for (int i = 0; i < data.size(); ++i) {
            int val = data[i];
            for (int j = 0; j < data.size(); ++j) {
                if (j != i && data[j] % 2 == 0) {
                    result += val + data[j];
                }
            }
        }
        return result;
    }

    void addData(int d) {
        data.push_back(d);
    }
};

